var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"급보입니다, 알렌 경!","JPN":"急報です、バーミンガム卿！","ENG":"Sir Allen! Urgent news!","TWN":"速報，艾倫大人！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"적들이 좌익의 취약점을 공략하고 있습니다!","JPN":"敵が左翼の脆弱ポイントを攻略しています！","ENG":"The enemies are doing damage to the left wing!","TWN":"敵人正在攻擊左翼的弱點！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"증원을 통해 간신히 방어했지만, 이대로는 돌파당할 수 있습니다!","JPN":"増援によってなんとか防ぎましたが、このままでは突破される可能性があります！","ENG":"We have dispatched more troops to stop them, but it is a matter of time before they break through!","TWN":"透過增援勉強防住了，但這樣下去會被突破的！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"용병단에 비하면 소수인데도 쉽지 않군.","JPN":"傭兵隊に比べたら少数であるにもかかわらず、中々手強いな。","ENG":"They have fewer people than the Mercenaries... It's still not an easy fight.","TWN":"人數雖然比傭兵隊時要少，但是不容易對付呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L7_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"7번대에 투입 지시를 전해라. 우익은 선회하여 좌익의 측면으로 지원한다.","JPN":"7番隊に投入を指示しろ。右翼は旋回して左翼の側面から支援する。","ENG":"Dispatch Squad 7. Have the right wing turn and support the left wing.","TWN":"指示第7小隊投入戰鬥。讓右翼繞到左翼側面支援。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"예? 하지만 알렌 경, 그렇게 하면 퇴로가 열리지 않습니까?","JPN":"はい？　しかしバーミンガム卿、それでは退路が開いてしまうのでは？","ENG":"Pardon? But Sir Allen, wouldn't we be opening up their escape route?","TWN":"什麼？可是艾倫大人，那樣的話不就白白為敵人打開退路了嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"퇴각을 고려하지 않는 자들 상대로 퇴로를 닫아 봤자 아무런 의미도 없다.","JPN":"退却を考えていない者たちを相手に退路を閉じても意味はない。","ENG":"There's no point in cornering an enemy who does not seek to retreat.","TWN":"對於不考慮撤退的人來說，堵住退路也沒有任何意義。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"저들의 목적은 여기서 살아남는 게 아니다. 분명 구원자를 노리고 있겠지.","JPN":"あの者たちの目的はここで生き延びることではない。きっと救世主を狙っているんだろう。","ENG":"Their objective is not to survive, but to take down the Savior.","TWN":"那些人的目的不是存活，他們盯上的是救贖者。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"저들이 구원자님을……!","JPN":"あの者たちが救世主様を……！","ENG":"The Savior...!","TWN":"那些人盯上了救贖者……！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"KNIGHT_NPC_CHIEF_NULL","text":{"KOREA":"알겠습니다! 바로 우익에 신호를 보내겠습니다!","JPN":"かしこまりました！　すぐに右翼に合図を出します！","ENG":"Yes, sir! I shall signal the right wing straight away!","TWN":"遵命！我馬上指示右翼！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"THEMA_FENRIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KNIGHT_NPC_CHIEF_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"고작 네 명으로 중과부적의 병력에 맞서다니, 그림으로 남겨 두고 싶을 정도로군.","JPN":"たかが四人で大軍を相手に対抗しようなんて、絵にして残しておきたいくらいだ。","ENG":"Four versus an entire army. It would look great painted.","TWN":"只靠四個人對抗千軍萬馬，我都想把此刻留為畫作了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L19_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"전하.","JPN":"殿下。","ENG":"Your Highness.","TWN":"殿下。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"기세가 대단하지만 그것도 오래 가지 못할 겁니다.","JPN":"敵も、ものすごい勢いですが、あまり長くは持たないでしょう。","ENG":"They are pushing in with force, but it won't last long.","TWN":"雖然來勢洶洶，但是他們這樣堅持不了多久。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"축차 공격으로 체력을 소모시키면 저희의 승리입니다.","JPN":"戦力を逐次投入し、体力を削っていけば我々の勝利です。","ENG":"By continuously dispatching troops, we will be able to wear them out.","TWN":"只要用打游擊的方式消耗他們的體力，我們就贏了。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"진심으로 그렇게 생각하나, 알렌 경?","JPN":"本気でそう思うか、アレン？","ENG":"Do you really think so, Sir Allen?","TWN":"你真的那麼覺得嗎，艾倫卿？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저들의 맹주는 발키리다.","JPN":"奴らの盟主はヴァルキリーだ。","ENG":"Their leader is the Valkyrie.","TWN":"領隊的可是女武神。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"녹슬어 버린 지금도, 모습을 드러내는 것만으로 열세였던 전황을 첨예하게 만들었지.","JPN":"力が衰えた今でも、姿を現しただけで劣勢だった戦況を尖鋭に変えた。","ENG":"Even in her current rusty state, she managed to change the atmosphere just by showing up.","TWN":"在實力大減的現在，僅僅是露面就讓原本處於劣勢的戰局變得撲朔迷離。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"상식적인 전쟁에 머물러 있어선 결국 저들에게 틈을 줄 뿐이다.","JPN":"常識の範疇内でこの戦争を考えていては、結局連中に隙を与えるだけだ。","ENG":"Thinking inside the boundaries of regular battle will do nothing but provide them with more openings.","TWN":"若是思維還停留在常規戰爭中的話，只會給他們可乘之機。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마르티네즈 공이 최전선에서 병력을 독려하고 있습니다.","JPN":"マルチネス卿が最前線で兵士たちを督励しています。","ENG":"Marquise Martinez is struggling with her best in the frontlines.","TWN":"馬汀尼茲侯爵正在最前線鼓舞士兵的士氣。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"그녀만으로는 부족하다고 판단하신 겁니까?","JPN":"彼女だけでは足りないと判断されたのですか？","ENG":"Is it that you assume that she's not enough?","TWN":"您認為光靠她還不夠嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"부족하지. 겨우 알을 깨고 일어선 병아리에게는.","JPN":"足りるわけがない。タマゴから孵化したばかりのヒヨコではな。","ENG":"For a mere fledgling who just broke out of her shell, of course it's not enough.","TWN":"對於剛剛破殼而出的雛鳥來說，當然不夠。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"승리하든 패배하든 이 곳이 우리의 마지막 전장이다.","JPN":"勝利しようが敗北しようが、ここが私たちの最後の戦場だ。","ENG":"Regardless of the outcome, this will be our last battle.","TWN":"不管勝敗如何，這裡都是我們最後的戰場。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"저들이 각오를 보였으니, 우리도 보여 줘야 마땅하지 않겠나.","JPN":"彼らが覚悟を見せてくれたんだ、我々も見せるべきではないか。","ENG":"Our enemies have shown us their determination and so shall we.","TWN":"既然他們已經做好了心理準備，我們也要有所表現吧？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"우리에게도 지켜야 할 것이 있고, 이루고 싶은 것이 존재한다는 것을.","JPN":"我々にも守るべきものがある、そして叶えたいものがあると。","ENG":"We, too, shall show them that we have things to protect and yearn for.","TWN":"我們也有要守護的東西，也有想實現的夢想。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"설령 이제는 망자들의 군단에 불과할지라도.","JPN":"たとえ、もはや亡者たちの軍団に過ぎないとしてもな。","ENG":"Even if we are none but an army of the deceased.","TWN":"哪怕我們現在只是一群死人，是一群死人組成的軍隊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"그러니 알렌 경, 그대도 신하가 아니라 같은 기사로서 대답해 주기 바란다.","JPN":"だからアレン、そなたも臣下ではなく同じ騎士として答えてくれ。","ENG":"So, Sir Allen, I ask you to reciprocate, not as a servant, but as a knight.","TWN":"所以艾倫卿，我希望你也作為騎士，而不是臣子來回答我的問題。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"마지막까지 전하의 변덕을 혼자 감당해야 한다는 사실이 애석할 따름입니다.","JPN":"最後まで殿下の気まぐれに一人で耐えなければならないことが悲しいだけです。","ENG":"It is truly a shame that I alone have to take care of your volatile nature, Your Highness.","TWN":"看來直到最後，我還是要獨自承受殿下的善變。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"호위는 필요하지 않으십니까?","JPN":"護衛は要りませんか？","ENG":"Will you be needing any bodyguards?","TWN":"您不需要護衛嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"여긴 사방에서 피가 끓고 철이 맞부딪치는 곳이다.","JPN":"ここはそこかしこで血が煮えくり返り、鉄がぶつかりあう場所だ。","ENG":"The battlefield is where blood is shed and blades collide.","TWN":"在這短兵相接、四面楚歌之地，"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PRINCE_KNIGHT_NULL_NULL","text":{"KOREA":"호위 따위를 기대하려면……. 처음부터 발을 들이지 말았어야지.","JPN":"護衛などを期待するぐらいなら……最初から踏み入る場所ではない。","ENG":"If I were to expect such a thing... I should not have taken part in this in the first place.","TWN":"要是期待護衛什麼的……一開始就不該踏足這裡。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRINCE_KNIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"……그렇군요.","JPN":"……そうですか。","ENG":"...I see.","TWN":"……這樣啊。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L48_1","type":"dialog","speaker":"ALLEN_ORDER_NULL_NULL","text":{"KOREA":"기다리고 있겠습니다, 전하. 부디 무사히 돌아오십시오.","JPN":"お待ちしております、殿下。どうか無事にお戻りください。","ENG":"I will be waiting, Your Highness. I wish for your safe return.","TWN":"我會等著您，殿下。您一定要平安歸來。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};